import.single:
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion"

tokens.customizationCode:
/* Aumentar separador entre itens */
.my-accordion .mbds-accordion-item {
  border-bottom-width: 2px;
  border-color: hsl(var(--border) / 60%);
}

/* Trigger com background em hover */
.my-accordion .mbds-accordion-trigger:hover {
  background-color: hsl(var(--muted) / 0.4);
  border-radius: 0.375rem;
}

